def select_next_node(cur_truck_pos, depot_pos, all_truck_pos, unvisited_customers, current_time, truck_speed, time_windows):
    def calculate_distance(point1, point2):
        return np.linalg.norm(point1 - point2)

    priority_scores = []
    for idx, customer_pos in enumerate(unvisited_customers):
        travel_time = calculate_distance(cur_truck_pos, customer_pos) / truck_speed
        arrival_time = current_time + travel_time
        start_window, end_window = time_windows[idx]

        time_window_factor = max(0, arrival_time - end_window) if arrival_time > end_window else (start_window - arrival_time) if arrival_time < start_window else -1
        combined_score = time_window_factor + travel_time  # basic score combining window urgency and travel time

        # Adapt score based on other trucks' positions, potentially improving the decision base on collaboration chances
        for other_truck_pos in all_truck_pos:
            if np.array_equal(other_truck_pos, cur_truck_pos):
                continue
            other_travel_time = calculate_distance(other_truck_pos, customer_pos) / truck_speed
            other_arrival_time = current_time + other_travel_time
            if other_arrival_time < arrival_time:
                combined_score += 5  # increase priority to reinforce that this truck should hurry to the customer because other trucks are also potentially reaching there soon

